        memo[x] = 1 + popcountDepth(next);
        return memo[x];
    }

    // Memoized function for popcount-depth
    const dp = memoize(popcountDepth);

    // Count numbers with popcount-depth exactly equal to k
    let count = 0;
    for (let i = 1; i <= n; i++) {
        if (dp(i) === k) {
